class AppError extends Error {
  constructor(message, statusCode, code, details = null) {
    super(message);
    this.statusCode = statusCode;
    this.code       = code;
    this.details    = details;
    this.isOperational = true;
  }

  static notFound(resource = 'Ressource') {
    return new AppError(`${resource} introuvable`, 404, 'NOT_FOUND');
  }
  static unauthorized() {
    return new AppError('Non authentifié', 401, 'UNAUTHORIZED');
  }
  static validation(details) {
    return new AppError('Données invalides', 422, 'VALIDATION_ERROR', details);
  }
}

function errorHandler(err, req, res, next) {
  const requestId = req.headers['x-request-id'] || crypto.randomUUID();

  if (err.isOperational) {
    return res.status(err.statusCode).json({
      error: {
        code:    err.code,
        message: err.message,
        details: err.details,
        requestId,
      },
    });
  }

  res.status(500).json({
    error: { code: 'INTERNAL_ERROR', message: 'Erreur interne', requestId },
  });
}

module.exports = { AppError, errorHandler };
